 53     // in the def-use chain needs to be changed.
 54     auto *J = dyn_cast<Instruction>(JU);
 55     if (J && J->getType()->isIntOrIntVectorTy() &&
 56         !DB.getDemandedBits(J).isAllOnes()) {
 57       Visited.insert(J);
