563 void Instruction::andIRFlags(const Value *V) {
564   if (auto *OB = dyn_cast<OverflowingBinaryOperator>(V)) {
565     if (isa<OverflowingBinaryOperator>(this)) {
566       setHasNoSignedWrap(hasNoSignedWrap() && OB->hasNoSignedWrap());
567       setHasNoUnsignedWrap(hasNoUnsignedWrap() && OB->hasNoUnsignedWrap());
568     }
569   }
570 
571   if (auto *PE = dyn_cast<PossiblyExactOperator>(V))
572     if (isa<PossiblyExactOperator>(this))
573       setIsExact(isExact() && PE->isExact());
574 
575   if (auto *SrcPD = dyn_cast<PossiblyDisjointInst>(V))
576     if (auto *DestPD = dyn_cast<PossiblyDisjointInst>(this))
577       DestPD->setIsDisjoint(DestPD->isDisjoint() && SrcPD->isDisjoint());
578 
579   if (auto *FP = dyn_cast<FPMathOperator>(V)) {
580     if (isa<FPMathOperator>(this)) {
581       FastMathFlags FM = getFastMathFlags();
582       FM &= FP->getFastMathFlags();
583       copyFastMathFlags(FM);
